param([string]$To="alex@1v1a.com",[string]$From="sales@vectarr.com",[string]$Subject="Test 2/7 - sales@vectarr.com Signature Test")
try{$s=Get-Content "$env:APPDATA\Microsoft\Signatures\sales_signature.htm"-Raw;$o=New-Object -ComObject Outlook.Application;$m=$o.CreateItem(0);$m.To=$To;$m.Subject=$Subject;$m.HTMLBody="<!DOCTYPE html><html><head><meta charset='UTF-8'></head><body><div style='font-family:Segoe UI,Arial,sans-serif;font-size:14px'>Test email 2 of 7 from Vectarr/TypeWrite accounts.<br><br>Testing sales@vectarr.com signature</div>$s</body></html>";$a=$o.Session.Accounts|Where-Object{$_.SmtpAddress-eq$From};if($a){$m.SendUsingAccount=$a;Write-Host "Email 2/7 sent from $From"}else{Write-Warning "Account not found";exit 1};$m.Send()}catch{Write-Error "Failed: $_";exit 1}finally{if($m){[System.Runtime.Interopservices.Marshal]::ReleaseComObject($m)|Out-Null}if($o){[System.Runtime.Interopservices.Marshal]::ReleaseComObject($o)|Out-Null}}